import{_ as t,a,b as d,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as r,o,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"WebDAV Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/webdav.md","filePath":"ta/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"ta/upload/webdav.md"};function c(p,e,h,u,b,f){return o(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="webdav-channel-சேர்க்கவும்" tabindex="-1">WebDAV Channel சேர்க்கவும் <a class="header-anchor" href="#webdav-channel-சேர்க்கவும்" aria-label="Permalink to &quot;WebDAV Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="எப்போது-பயன்படுத்துவது" tabindex="-1">எப்போது பயன்படுத்துவது <a class="header-anchor" href="#எப்போது-பயன்படுத்துவது" aria-label="Permalink to &quot;எப்போது பயன்படுத்துவது&quot;">​</a></h2><p>WebDAV channel பயன்படுத்தலாம், நீங்கள்:</p><ul><li>NAS, cloud drive, அல்லது WebDAV endpoint வழங்கும் object storage service வைத்திருந்தால்.</li><li>uploaded images உங்கள் சொந்த WebDAV directory-ல் சேமிக்க வேண்டும் என்றால்.</li><li>credentials-ஐ frontend-ல் நீண்ட நேரம் expose செய்யாமல் D1 <code>upload_channels</code> table-ல் சேமிக்க விரும்பினால்.</li></ul><h2 id="தொடங்குவதற்கு-முன்-தேவையானவை" tabindex="-1">தொடங்குவதற்கு முன் தேவையானவை <a class="header-anchor" href="#தொடங்குவதற்கு-முன்-தேவையானவை" aria-label="Permalink to &quot;தொடங்குவதற்கு முன் தேவையானவை&quot;">​</a></h2><table tabindex="0"><thead><tr><th>தேவை</th><th>பயன்பாடு</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>server-side WebDAV URL, உதா. <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>WebDAV service-க்கு sign in செய்ய.</td></tr><tr><td>Password</td><td>WebDAV service-க்கு sign in செய்ய.</td></tr><tr><td>Authentication mode</td><td>default <code>Basic</code>. server கேட்கும் போது மட்டும் <code>Digest</code> அல்லது auto negotiation.</td></tr><tr><td>Storage directory</td><td>files சேமிக்கப்படும் directory. default <code>imgbed</code>.</td></tr></tbody></table><h2 id="எங்கு-சேர்ப்பது" tabindex="-1">எங்கு சேர்ப்பது <a class="header-anchor" href="#எங்கு-சேர்ப்பது" aria-label="Permalink to &quot;எங்கு சேர்ப்பது&quot;">​</a></h2><ol><li>System Settings திறக்கவும்.</li><li>Upload Settings-க்கு செல்லவும்.</li><li>மேல் வலது மூலையில் Add Channel கிளிக் செய்யவும்.</li><li><code>WebDAV</code> தேர்வு செய்யவும்.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>பயன்பாடு</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>இந்த WebDAV channel-க்கு பெயர், உதா. <code>koofr</code> அல்லது <code>nas</code>.</td><td>Yes</td></tr><tr><td>Endpoint</td><td>முழு WebDAV endpoint, <code>https://</code> உடன்.</td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username.</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password.</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>பொதுவாக <code>Basic</code>; server digest authentication கேட்கும் போது <code>Digest</code>.</td><td>Yes</td></tr><tr><td>Storage directory</td><td>files சேமிக்கப்படும் directory. default <code>imgbed</code>.</td><td>No</td></tr></tbody></table><h2 id="example-fie-nl-tab-digital" tabindex="-1">Example: fie.nl.tab.digital <a class="header-anchor" href="#example-fie-nl-tab-digital" aria-label="Permalink to &quot;Example: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-app-password-உருவாக்கவும்" tabindex="-1">1. App Password உருவாக்கவும் <a class="header-anchor" href="#_1-app-password-உருவாக்கவும்" aria-label="Permalink to &quot;1. App Password உருவாக்கவும்&quot;">​</a></h3><p>account security settings திறந்து application passwords பகுதியைத் தேடி புதிய app password உருவாக்கவும்.</p><p><img src="'+t+'" alt="Create an app password" loading="lazy"></p><p>உருவானதும் app password-ஐ copy செய்து சேமிக்கவும். இது பொதுவாக ஒருமுறை மட்டுமே காட்டப்படும்.</p><p><img src="'+a+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-imgbed-ல்-webdav-configuration-நிரப்பவும்" tabindex="-1">2. ImgBed-ல் WebDAV Configuration நிரப்பவும் <a class="header-anchor" href="#_2-imgbed-ல்-webdav-configuration-நிரப்பவும்" aria-label="Permalink to &quot;2. ImgBed-ல் WebDAV Configuration நிரப்பவும்&quot;">​</a></h3><p>ImgBed-க்கு திரும்பி WebDAV channel சேர்க்கவும்:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td><code>https://fie.nl.tab.digital/</code> வழங்கும் WebDAV URL.</td></tr><tr><td>Username</td><td>உங்கள் WebDAV username.</td></tr><tr><td>Password</td><td>நீங்கள் இப்போது உருவாக்கிய app password.</td></tr><tr><td>Authentication mode</td><td>அதிகப்படியான சந்தர்ப்பங்களில் <code>Basic</code>-இல் தொடங்கவும்.</td></tr><tr><td>Storage directory</td><td>default <code>imgbed</code>; தேவையெனில் custom directory.</td></tr></tbody></table><p><img src="'+d+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="large-file-upload-behavior" tabindex="-1">Large File Upload Behavior <a class="header-anchor" href="#large-file-upload-behavior" aria-label="Permalink to &quot;Large File Upload Behavior&quot;">​</a></h2><p>WebDAV channel இப்போது real session-based chunked upload பயன்படுத்துகிறது.</p><p>சிறிய files ஒரே complete file ஆக upload ஆகும். 64 MiB-ஐ விட பெரிய files தானாக சுமார் 10 MiB chunks ஆகப் பிரிந்து remote chunk directory-ல் upload ஆகும்.</p><p>WebDAV service <code>partial update</code> அல்லது offset-based writes support செய்ய வேண்டியதில்லை. ImgBed remote server-ல் chunks-ஐ ஒரு பெரிய file ஆக merge செய்யாது. அதற்கு பதில் chunk manifest சேமித்து, file request வரும் போது chunks-ஐ வரிசையாக படிக்கும்.</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB அல்லது குறைவு</td><td>Normal upload</td><td>ஒரு complete file</td></tr><tr><td>64 MiB-ஐ விட பெரியது</td><td>Real session chunked upload</td><td>பல chunk files உள்ள chunk directory</td></tr></tbody></table><p>chunk directory remote storage layout-ஐ மட்டும் பாதிக்கும். ImgBed file URL மாறாது. users original <code>/file/...</code> link மூலமே file access செய்வார்கள்.</p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings திறக்கவும்.</li><li>Add Channel கிளிக் செய்யவும்.</li><li><code>WebDAV</code> தேர்வு செய்யவும்.</li><li>அறியக்கூடிய channel name உள்ளிடவும், உதா. <code>koofr</code>.</li><li>WebDAV endpoint உள்ளிடவும், உதா. <code>https://app.koofr.net/dav/Koofr</code>.</li><li>username மற்றும் password உள்ளிடவும்.</li><li>authentication mode-ஐ default <code>Basic</code> ஆக வைத்திருக்கவும்.</li><li>storage directory-ஐ <code>imgbed</code> ஆக வைத்திருக்கலாம்; இல்லையெனில் உங்கள் directory கொடுக்கலாம்.</li><li>Save கிளிக் செய்யவும்.</li><li>பிறகு channel card, capacity query, test file upload ஆகியவற்றைச் சரிபார்க்கவும்.</li></ol><h2 id="verify-செய்வது" tabindex="-1">Verify செய்வது <a class="header-anchor" href="#verify-செய்வது" aria-label="Permalink to &quot;Verify செய்வது&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>சரிபார்ப்பு</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save செய்த பிறகு Upload Settings-ல் WebDAV channel card தெரியும்.</td></tr><tr><td>Channel is enabled</td><td>card switch on ஆகவே இருக்கும்.</td></tr><tr><td>Credentials are saved</td><td>detail view-ல் Endpoint, username, authentication mode, storage directory தெரியும்.</td></tr><tr><td>Small file upload works</td><td>test image upload செய்து WebDAV directory-ல் file வந்ததா பார்க்கவும்.</td></tr><tr><td>Large file rule works</td><td>64 MiB-ஐ விட பெரிய files chunked upload பயன்படுத்தி remote chunk directory உருவாக்கும்.</td></tr><tr><td>Capacity query works</td><td>server capacity information support செய்தால் used/total capacity தெரியும்.</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="பெரிய-webdav-files-chunk-directory-ஏன்-உருவாக்குகின்றன" tabindex="-1">பெரிய WebDAV files chunk directory ஏன் உருவாக்குகின்றன? <a class="header-anchor" href="#பெரிய-webdav-files-chunk-directory-ஏன்-உருவாக்குகின்றன" aria-label="Permalink to &quot;பெரிய WebDAV files chunk directory ஏன் உருவாக்குகின்றன?&quot;">​</a></h3><p>இது large files-க்கான தற்போதைய storage method.</p><p>64 MiB-ஐ விட பெரிய files remote side-ல் ஒரு பெரிய file ஆக merge ஆகாது. அவை chunk directory ஆக சேமிக்கப்படும். ImgBed chunk manifest record செய்து complete content-ஐ chunks-ஐ வரிசையாக படித்து தரும்.</p><h3 id="large-file-upload-fail-ஆனால்-முதலில்-என்ன-பார்க்க-வேண்டும்" tabindex="-1">large file upload fail ஆனால் முதலில் என்ன பார்க்க வேண்டும்? <a class="header-anchor" href="#large-file-upload-fail-ஆனால்-முதலில்-என்ன-பார்க்க-வேண்டும்" aria-label="Permalink to &quot;large file upload fail ஆனால் முதலில் என்ன பார்க்க வேண்டும்?&quot;">​</a></h3><p>Endpoint, username, password, storage directory சரியா பார்க்கவும். WebDAV service directory creation, file writing, file reading allow செய்கிறதா உறுதிசெய்யவும்.</p><p>capacity query fail ஆனால் small file upload வேலை செய்கிறது என்றால், server capacity reporting support செய்யாமல் இருக்கலாம். அதனால் upload unavailable என்று அர்த்தமில்லை.</p><h3 id="எந்த-authentication-mode-பயன்படுத்துவது" tabindex="-1">எந்த authentication mode பயன்படுத்துவது? <a class="header-anchor" href="#எந்த-authentication-mode-பயன்படுத்துவது" aria-label="Permalink to &quot;எந்த authentication mode பயன்படுத்துவது?&quot;">​</a></h3><p><code>Basic</code>-இல் தொடங்கவும்.</p><p>server தெளிவாக digest authentication கேட்கின் <code>Digest</code> பயன்படுத்தவும்.</p><p>நிச்சயமில்லையெனில் automatic negotiation பயன்படுத்தவும்.</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV endpoint, username, password தயார் செய்யவும்</span></span>
<span class="line"><span>-&gt; Upload Settings திறக்கவும்</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; WebDAV தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; Endpoint / username / password நிரப்பவும்</span></span>
<span class="line"><span>-&gt; authentication mode default Basic வைத்திருக்கவும்</span></span>
<span class="line"><span>-&gt; storage directory default imgbed வைத்திருக்கவும்</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; capacity query</span></span>
<span class="line"><span>-&gt; test file upload</span></span></code></pre></div>`,44)])])}const k=r(s,[["render",c]]);export{y as __pageData,k as default};
